import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"TLDR AI — 2026-05-19","description":"","frontmatter":{"title":"TLDR AI — 2026-05-19","date":"2026-05-19T00:00:00.000Z","source":"TLDR AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-19-tldr-ai.md","filePath":"research/ai-news/2026-05/2026-05-19-tldr-ai.md","lastUpdated":1779894392000}'),n={name:"research/ai-news/2026-05/2026-05-19-tldr-ai.md"};function s(i,e,l,c,d,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="⚡-tldr-ai-—-2026-05-19" tabindex="-1">⚡ TLDR AI — 2026-05-19 <a class="header-anchor" href="#⚡-tldr-ai-—-2026-05-19" aria-label="Permalink to &quot;⚡ TLDR AI — 2026-05-19&quot;">​</a></h1><blockquote><p>5 分鐘科技簡報，AI + 程式 + 產品精華濃縮 來源：<a href="https://tldr.tech/api/rss/ai" target="_blank" rel="noreferrer">TLDR AI</a></p></blockquote><hr><h2 id="gemini-extended-thinking-✨-chatgpt-finance-📱-claude-code-at-scale-👨‍💻" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-18" target="_blank" rel="noreferrer">Gemini Extended Thinking ✨, ChatGPT finance 📱, Claude Code at scale 👨‍💻</a> <a class="header-anchor" href="#gemini-extended-thinking-✨-chatgpt-finance-📱-claude-code-at-scale-👨‍💻" aria-label="Permalink to &quot;[Gemini Extended Thinking ✨, ChatGPT finance 📱, Claude Code at scale 👨‍💻](https://tldr.tech/ai/2026-05-18)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-18</em></p><p><strong><a href="https://openai.com/index/personal-finance-chatgpt/?utm_source=tldrai" target="_blank" rel="noreferrer">ChatGPT Personal Finance (6 minute read)</a></strong> OpenAI released a preview of a new personal finance experience in ChatGPT for Pro users in the US. The feature lets users securely connect financial accounts, view spending dashboards, and ask questions grounded in their financial context and goals. <strong><a href="https://9to5google.com/2026/05/17/gemini-app-thinking-level/?utm_source=tldrai" target="_blank" rel="noreferrer">Gemini app rolling out ‘Extended&#39; thinking level, new 3rd-party app integrations (3 minute read)</a></strong> Google is rolling out a new &#39;Thinking level&#39; option for Gemini. The option has appeared for some users when they select Fast or Gemini 3.1 Pro. Google is also preparing to add more integrations with third-party apps in Gemini. Support for Canva, Instacart, and OpenTable appears to be coming. <strong><a href="https://www.testingcatalog.com/openai-will-let-codex-control-other-desktop-devices-via-computer-use/?utm_source=tldrai" target="_blank" rel="noreferrer">Codex will soon be able to control other desktop devices via Computer Use (2 minute read)</a></strong> OpenAI is working on a capability that lets its coding agent operate macOS applications through Computer Use even when a laptop is locked or asleep. Computer Use currently requires an unlocked, awake session to see the screen, move the cursor, and type. Lifting the restriction will allow users to direct their agents without having to walk back to their machines to log in first. It is unknown when the feature will be released. <strong><a href="https://x.com/sriramkri/status/2054594308494229882?utm_source=tldrai" target="_blank" rel="noreferrer">AI economics part 2 (11 minute read)</a></strong> AI labs are in an ongoing war over GPU resources. That article looks into demand and supply and how the infrastructure powering AI today may not be sufficient. Scaling GPUs doesn&#39;t scale compute linearly. Efficiency matters more at raw scale given finite supply. <strong><a href="https://x.com/PatrickToulme/status/2055709800986780028?utm_source=tldrai" target="_blank" rel="noreferrer">Portability Is a Myth: Why the Best AI Stacks Will Never Be Hardware-Agnostic (15 minute read)</a></strong> AI kernel portability is structurally impossible because TPU&#39;s Pallas, NVIDIA&#39;s CuTile and CUTLASS, AWS&#39;s NKI, AMD&#39;s FlyDSL, and Tenstorrent&#39;s tt-Metalium each expose hardware-specific concepts that no universal DSL can unify. The evidence: MaxText&#39;s MoE grouped matmul ships as 282 lines of Pallas on TPU while flashinfer&#39;s equivalent for Blackwell SM100 takes 4 million lines of generated CUDA, with zero shared code because the algorithms themselves diverge across hardware. <strong><a href="https://skids.dev/blog/anthropic-cache-tokenomics/?utm_source=tldrai" target="_blank" rel="noreferrer">Tokenomics: the 62.5-minute rule for Claude&#39;s cache (8 minute read)</a></strong> If you expect to need a cache before 62.5 minutes, refresh it. Otherwise, let it expire. This number stays the same between models, and it doesn&#39;t change, no matter the size of the cache. The amount of dollars may change, but the decision point is still the same. <strong><a href="https://claude.com/blog/how-claude-code-works-in-large-codebases-best-practices-and-where-to-start?utm_source=tldrai" target="_blank" rel="noreferrer">How Claude Code works in large codebases: Best practices and where to start (5 minute read)</a></strong> Claude Code is now being used in production across multiple large codebases in organizations with thousands of developers. These environments bring challenges that smaller codebases don&#39;t. This article covers patterns that Anthropic has seen that have led to the successful adoption of Claude Code at scale. It looks at how Claude Code has been used in monorepos with millions of lines, legacy systems built over decades, and microservices across separate repositories. <strong><a href="https://magazine.sebastianraschka.com/p/recent-developments-in-llm-architectures?utm_source=tldrai" target="_blank" rel="noreferrer">Recent Developments in LLM Architectures: KV Sharing, mHC, and Compressed Attention (33 minute read)</a></strong> KV-cache size, memory traffic, and attention cost quickly become the main constraints as reasoning models and agent workflows keep more tokens around for longer. LLM developers are adding a growing number of architecture tricks to reduce costs. Most of the changes look like small tweaks, but some are quite intricate design changes. This article looks at these architecture changes with a focus on what changes inside the transformer block, residual stream, KV cache, and attention computation. <strong><a href="https://nousresearch.com/lighthouse-attention?utm_source=tldrai" target="_blank" rel="noreferrer">Lighthouse Attention (11 minute read)</a></strong> Lighthouse Attention, a selection-based hierarchical attention, offers up to 17x faster forward and backward passes than standard attention models at large contexts. It utilizes FlashAttention on a dense sub-sequence, maintaining efficiency and compatibility with upstream improvements. By enabling efficient long-context training and retaining dense model competence, Lighthouse Attention achieves 1.4x to 1.7x speedup in pretraining while reducing computational costs. <strong><a href="https://www.dwarkesh.com/p/notes-on-pretraining-parallelisms?utm_source=tldrai" target="_blank" rel="noreferrer">Notes on pretraining parallelisms and failed training runs (12 minute read)</a></strong> Pretraining runs often fail. This article looks at all the ways that things can go wrong and why training is such a precarious operation. The key culprits seem to be breaking causality and adding bias. <strong><a href="https://techcrunch.com/2026/05/16/the-haves-and-have-nots-of-the-ai-gold-rush/?utm_source=tldrai" target="_blank" rel="noreferrer">The haves and have nots of the AI gold rush (1 minute read)</a></strong> The AI boom has created a wealth divide, with an estimated 10,000 individuals from companies like OpenAI and Nvidia achieving over $20M in wealth, while others face uncertain futures with stagnant job prospects and layoffs. Software engineers express concerns about their skills becoming obsolete, raising anxiety about career paths. This disparity fuels tension in San Francisco&#39;s tech scene as some criticize the dual role of AI as a wealth source and a career threat. <strong><a href="https://techcrunch.com/2026/05/15/runway-started-by-helping-filmmakers-now-it-wants-to-beat-google-at-ai/?utm_source=tldrai" target="_blank" rel="noreferrer">Runway started by helping filmmakers — now it wants to beat Google at AI (11 minute read)</a></strong> Runway&#39;s founders believe that the next form of AI will be built from video and world models that learn how the world works. The company is training models directly on observational data to reach the next frontier of AI. Runway was one of the first to develop AI video generation, but world models are a different race with deep-pocketed competitors. The company has raised $860 million to date, but it is going against incumbents like OpenAI and Google. <strong><a href="https://github.com/chopratejas/headroom?utm_source=tldrai" target="_blank" rel="noreferrer">Headroom (GitHub Repo)</a></strong> Headroom compresses everything an agent reads before it reaches the LLM to produce the same answers at a fraction of the tokens. <strong><a href="https://www.williamangel.net/blog/2026/05/17/offline-llm-energy-use.html?utm_source=tldrai" target="_blank" rel="noreferrer">Apple Silicon costs more than OpenRouter (3 minute read)</a></strong> Openrouter costs about 1/3 the price at around 2x the speed for comparable models. <strong><a href="https://www.seangoedecke.com/steering-vectors/?utm_source=tldrai" target="_blank" rel="noreferrer">DeepSeek-V4-Flash means LLM steering is interesting again (9 minute read)</a></strong> Steering is the idea that LLM outputs can be guided by directly manipulating the activations of a model mid-flight. <strong><a href="https://www.implicator.ai/openai-quietly-bought-voice-cloning-startup-weights-gg-then-folded-the-team/?utm_source=tldrai" target="_blank" rel="noreferrer">OpenAI Quietly Bought Voice-Cloning Startup Weights.gg, Then Folded the Team (3 minute read)</a></strong> OpenAI acquired the six-person team and its intellectual properties, then shut down Weights.gg and dispersed its team across multiple OpenAI groups. <strong><a href="https://jobs.ashbyhq.com/tldr.tech/3b21aaf8-dea5-4127-be71-602d30e5001e?utm_source=tldrai" target="_blank" rel="noreferrer">TLDR is hiring a Senior Software Engineer, Applied AI ($250k-$350k, Fully Remote)</a></strong> TLDR&#39;s Applied AI team is tasked with making every process at TLDR legible to code, runnable by anyone, and composable into larger workflows. Join a small, fast moving team using the latest AI tools with an unlimited token budget. Learn more .</p><hr><h2 id="grok-build-👨‍💻-codex-customizations-🤖-xai-exodus-👋" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-15" target="_blank" rel="noreferrer">Grok Build 👨‍💻 , Codex customizations 🤖, xAI exodus 👋</a> <a class="header-anchor" href="#grok-build-👨‍💻-codex-customizations-🤖-xai-exodus-👋" aria-label="Permalink to &quot;[Grok Build 👨‍💻 , Codex customizations 🤖, xAI exodus 👋](https://tldr.tech/ai/2026-05-15)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-15</em></p><p><strong><a href="https://x.ai/news/grok-build-cli?utm_source=tldrai" target="_blank" rel="noreferrer">Introducing Grok Build (2 minute read)</a></strong> Grok Build is a coding agent that runs from the terminal. It is now in early beta for SuperGrok Heavy subscribers. AGENTS.md, plugin, hooks, skills, and MCP servers all work out of the box. Grok Build supports subagents for larger tasks, and it also supports deep worktree integrations, so users can launch subagents in their own worktrees. There is a headless mode that allows the easy running of agents inside scripts and automations. <strong><a href="https://cursor.com/blog/cloud-agent-development-environments?utm_source=tldrai" target="_blank" rel="noreferrer">Cloud Agent Development Environments (6 minute read)</a></strong> Cursor detailed a new system for configuring cloud-based development environments tailored to autonomous coding agents. It supports multi-repo, environment configuration as code, automated setup workflows, and governance controls for managing fleets of parallel agents. <strong><a href="https://techcrunch.com/2026/05/14/openai-is-reportedly-preparing-legal-action-against-apple-it-wouldnt-be-the-first-partner-to-feel-burned/?utm_source=tldrai" target="_blank" rel="noreferrer">OpenAI Explores Legal Action Against Apple (1 minute read)</a></strong> Bloomberg reported that OpenAI explored legal options against Apple over dissatisfaction with how deeply ChatGPT was integrated into Apple&#39;s ecosystem and the limited subscriber growth that followed. <strong><a href="https://www.anthropic.com/research/2028-ai-leadership?utm_source=tldrai" target="_blank" rel="noreferrer">2028: Two scenarios for global AI leadership (28 minute read)</a></strong> Anthropic outlines two possible 2028 global AI leadership scenarios: one where the US retains its compute advantage and shapes AI norms, and another where China competes closely due to policy inaction. The US currently leads due to strong export controls and advanced chip technology preventing China from keeping pace. Closing loopholes on compute access and restricting distillation attacks are crucial for maintaining the US lead and ensuring democracies shape AI governance. <strong><a href="https://x.com/larsencc/status/2027225210412470668?utm_source=tldrai" target="_blank" rel="noreferrer">How We Built Secure, Scalable Agent Sandbox Infrastructure (8 minute read)</a></strong> There are two ways to sandbox an agent that can execute code: isolate the tool or isolate the agent. Agents should have nothing worth stealing and nothing worth reserving. Isolating the agent requires an extra network hop on every operation and more services to deploy, but there are no secrets to steal, no state to preserve, and agents can be killed, restarted, and scaled independently. <strong><a href="https://threadreaderapp.com/thread/2055032115964870838.html?utm_source=tldrai" target="_blank" rel="noreferrer">Codex is getting easier to automate and customize around your code (1 minute read)</a></strong> Codex has implemented hooks and programmatic tokens to make it easier to automate and customize code. Hooks can customize the Codex loop with scripts that run at key points in a task. Programmatic access provides scoped credentials for Business and Enterprise teams. A video showing how to create access tokens for Codex automations is available. <strong><a href="https://github.com/raindrop-ai/workshop?utm_source=tldrai" target="_blank" rel="noreferrer">Raindrop Workshop (GitHub Repo)</a></strong> Raindrop Workshop gives Claude Code the ability to read traces, write evals against codebases, and fix what&#39;s broken. It provides livestreamed traces, coding-agent integration, a self-healing eval loop, and local replay. Raindrop Workshop is compatible with TypeScript, Python, Go, and Rust, and most popular SDKs, providers, and coding agents. <strong><a href="https://developers.googleblog.com/announcing-genkit-middleware-intercept-extend-and-harden-your-agentic-apps/?utm_source=tldrai" target="_blank" rel="noreferrer">Genkit Middleware (10 minute read)</a></strong> Genkit is a framework for building full-stack, AI-powered and agentic applications for any platform. It supports TypeScript, Go, Dart, and Python. Genkit uses composable hooks that intercept generation calls to implement retries and fall-backs for maximum reliability, human approval before destructive tool calls, and observability across every layer. Its middleware system runs a tool loop that repeats until the model is done. The Genkit Developer can be used to inspect, test, and debug applications and middleware execution. <strong><a href="https://huggingface.co/blog/continuous_async?utm_source=tldrai" target="_blank" rel="noreferrer">Unlocking asynchronicity in continuous batching (20 minute read)</a></strong> Asynchronous batching can reduce idle time between CPU and GPU cycles, improving GPU utilization for inference by 22%. By using CUDA streams and events, CPU tasks prepare batch N+1 during batch N&#39;s GPU computation, eliminating idle gaps. This method yields more efficient GPU operations without changing kernels or models, enhancing generation speed substantially. <strong><a href="https://thenextweb.com/news/microsoft-startup-deals-life-after-openai?utm_source=tldrai" target="_blank" rel="noreferrer">Microsoft is quietly shopping for an OpenAI replacement (4 minute read)</a></strong> Microsoft signed a deal with OpenAI late April that amended the company&#39;s exclusive license to OpenAI models, freed OpenAI to sell on any other cloud, and removed the AGI clause that would have triggered changes to Microsoft&#39;s IP rights once OpenAI&#39;s board declared the threshold reached. Microsoft&#39;s IP license, a 27% stake worth roughly $135 billion, will be kept through 2032. Microsoft is reportedly looking to purchase Inception, a company that builds diffusion-based language models. It is interesting that Microsoft would spend $13 billion on a partner and then immediately start a shadow procurement process for a replacement. <strong><a href="https://techcrunch.com/2026/05/14/elon-musks-spacexai-has-been-bleeding-staff-since-its-merger/?utm_source=tldrai" target="_blank" rel="noreferrer">Elon Musk&#39;s SpaceXAI has been bleeding staff since its merger (2 minute read)</a></strong> SpaceXAI is reportedly losing top talent across coding, world models, and Grok voice. Rivals like Meta and Thinking Machines Lab are scooping up former staff. Elon Musk&#39;s culture of extreme work has led some staff to leave. Several of the exits could have been driven by a desire to cash out. <strong><a href="https://letsdatascience.com/news/igor-babuschkin-seeks-up-to-1-billion-for-river-ai-8c36ce09?utm_source=tldrai" target="_blank" rel="noreferrer">Igor Babuschkin Seeks Up To $1 Billion For River AI (3 minute read)</a></strong> Babuschkin, an xAI cofounder, is putting in $100 million of his own money into the company. <strong><a href="https://www.cnbc.com/2026/05/13/google-deepmind-alumni-startup-partners-nvidia-superintelligence.html?utm_source=tldrai" target="_blank" rel="noreferrer">Nvidia&#39;s Jensen Huang bets on this British startup to build &#39;next frontier&#39; of AI (3 minute read)</a></strong> Nvidia has announced a partnership with Ineffable Intelligence, a startup pursuing superintelligence that was founded in late 2025 by UCL professor and former lead of DeepMind&#39;s reinforcement learning team, David Silver. <strong><a href="https://openai.com/index/work-with-codex-from-anywhere/?utm_source=tldrai" target="_blank" rel="noreferrer">Work with Codex from anywhere (6 minute read)</a></strong> Codex is now available in the ChatGPT mobile app, enabling seamless remote access to ongoing work on laptops, devboxes, or remote environments. <strong><a href="https://www.testingcatalog.com/opensquilla-launches-open-source-ai-agent-to-cut-token-costs/?utm_source=tldrai" target="_blank" rel="noreferrer">OpenSquilla launches open-source AI agent to cut token costs (4 minute read)</a></strong> OpenSquilla has introduced an open-source AI agent runtime designed to reduce unnecessary token spend by reusing context efficiently. <strong><a href="https://jobs.ashbyhq.com/tldr.tech/3b21aaf8-dea5-4127-be71-602d30e5001e?utm_source=tldrai" target="_blank" rel="noreferrer">TLDR is hiring a Senior Software Engineer, Applied AI ($250k-$350k, Fully Remote)</a></strong> TLDR&#39;s Applied AI team is tasked with making every process at TLDR legible to code, runnable by anyone, and composable into larger workflows. Join a small, fast moving team using the latest AI tools with an unlimited token budget. Learn more . <strong><a href="https://www.datadoghq.com/blog/ai/toto-2/?utm_source=tldrai" target="_blank" rel="noreferrer">Toto 2.0: Time series forecasting enters the scaling era (13 minute read)</a></strong> Datadog&#39;s Toto 2.0, a scalable time series forecasting model family, is now available on Hugging Face.</p><hr><h2 id="claude-small-business-💼-anthropic-cfo-interview-💰-ai-adoption-data-📊" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-14" target="_blank" rel="noreferrer">Claude small business 💼, Anthropic CFO interview 💰, AI adoption data 📊</a> <a class="header-anchor" href="#claude-small-business-💼-anthropic-cfo-interview-💰-ai-adoption-data-📊" aria-label="Permalink to &quot;[Claude small business 💼, Anthropic CFO interview 💰, AI adoption data 📊](https://tldr.tech/ai/2026-05-14)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-14</em></p><p><strong><a href="https://www.bloomberg.com/news/articles/2026-05-13/ai-chipmaker-cerebras-said-poised-to-price-ipo-at-185-per-share?accessToken=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzb3VyY2UiOiJTdWJzY3JpYmVyR2lmdGVkQXJ0aWNsZSIsImlhdCI6MTc3ODczNzQxMCwiZXhwIjoxNzc5MzQyMjEwLCJhcnRpY2xlSWQiOiJURVpBQ0RLR1pBTlYwMCIsImJjb25uZWN0SWQiOiJFQTExNDNDNTM4NEE0RUY5QTg5RjJEN0IxMTg2MzcwOSJ9.endVGzrG2TUoxAqNLMDSjsM6mb_EML5ttpWnDsQfXJw&amp;utm_source=tldrai" target="_blank" rel="noreferrer">AI Chipmaker Cerebras Raises $5.55 Billion in Year&#39;s Biggest IPO (4 minute read)</a></strong> Cerebras raised $5.5 billion in its US IPO at a market valuation of about $40 billion. This was the largest IPO this year so far. The IPO drew orders for more than 20 times the number of shares available. The offering was led by Morgan Stanley, Citigroup, Barclays, and UBS. <strong><a href="https://www.anthropic.com/news/claude-for-small-business?utm_source=tldrai" target="_blank" rel="noreferrer">Claude for Small Business (8 minute read)</a></strong> Anthropic launched Claude for Small Business, a package of connectors and workflows that embeds Claude into tools like QuickBooks, PayPal, HubSpot, Google Workspace, and Microsoft 365. <strong><a href="https://econlab.substack.com/p/anthropic-beats-openai?utm_source=tldrai" target="_blank" rel="noreferrer">Anthropic beats OpenAI on business adoption (4 minute read)</a></strong> Anthropic has passed OpenAI in business adoption. More businesses used Anthropic than OpenAI in April. Anthropic has quadrupled business adoption over the last year, while OpenAI grew business adoption by only 0.3%. The pace of development in the AI industry is overriding the typical forces of vendor stickiness. <strong><a href="https://www.nytimes.com/2026/05/13/technology/recursive-superintelligence-funding-ai.html?unlocked_article_code=1.iVA.AOeV.mbXsnHhHx-oW&amp;smid=url-share&amp;utm_source=tldrai" target="_blank" rel="noreferrer">Notable Researchers Join $4 Billion Effort to Build Self-Improving AI (5 minute read)</a></strong> Recursive Superintelligence has raised more than $650 million at a valuation of more than $4 billion to build AI that can improve itself with little or no help from human developers. Its seven co-founders include notable researchers from many of the industry&#39;s leading AI companies. Many of these researchers specialize in AI systems that can run for long periods in pursuit of goals. While the researchers are bullish on the idea of AIs recursively improving themselves, the current technology is a long way from the point where humans can be removed from the loop. <strong><a href="https://openai.com/index/building-codex-windows-sandbox/?utm_source=tldrai" target="_blank" rel="noreferrer">How OpenAI Built the Codex Windows Sandbox (19 minute read)</a></strong> OpenAI detailed the engineering behind Codex&#39;s Windows sandbox, which constrained local commands, file access, and networking permissions while still allowing coding agents to operate effectively on developer machines. <strong><a href="https://vercel.com/blog/ai-gateway-production-index?utm_source=tldrai" target="_blank" rel="noreferrer">AI Gateway Production Trends (8 minute read)</a></strong> Vercel analyzed seven months of AI Gateway production traffic spanning hundreds of models and over 200,000 teams. The report showed rapid growth in agentic workloads, increasing adoption of open-source models, and heavy multi-model routing in large-scale deployments. <strong><a href="https://epochai.substack.com/p/the-economics-of-superstar-ai-researchers?utm_source=tldrai" target="_blank" rel="noreferrer">The economics of superstar AI researchers (12 minute read)</a></strong> Superstar researchers at frontier labs can earn over a hundred times more than the average AI postdoc. Researcher quantity doesn&#39;t easily make up for quality in the field of AI. Even a 2x researcher can earn far more than the median because their contributions easily scale to billions of users. If they can add something that multiple 1x researchers can&#39;t, then it&#39;s worth paying a lot to capture it. <strong><a href="https://www.testingcatalog.com/cline-releases-open-source-agent-runtime-sdk-for-coding-agents/?utm_source=tldrai" target="_blank" rel="noreferrer">Cline releases open-source agent runtime SDK for coding agents (3 minute read)</a></strong> @cline/sdk is an open-source framework for building agentic applications. It has a plugin architecture that makes it easy to customize, and the framework has all the features expected from agents, like checkpoints, web fetch, MCPs, cron jobs, subagents, and more. The SDK can be used to run agents from CI/CD pipelines, create automations for end-to-end workflows, or embed agents directly inside products. <strong><a href="https://www.perplexity.ai/hub/blog/how-we-built-security-into-computer?utm_source=tldrai" target="_blank" rel="noreferrer">Security Architecture Behind Perplexity Computer (2 minute read)</a></strong> Perplexity outlined the security systems powering its autonomous Computer agent, including Firecracker microVM isolation, scoped connector permissions, and prompt injection defenses. <strong><a href="https://pytorch.org/blog/pytorch-2-12-release-blog/?utm_source=tldrai" target="_blank" rel="noreferrer">PyTorch 2.12 Release Highlights (7 minute read)</a></strong> PyTorch 2.12 shipped major infrastructure updates including faster CUDA eigendecomposition, a unified graph capture API, MX quantization export support, and fused Adagrad optimizers. <strong><a href="https://www.geekwire.com/2026/microsofts-multi-agent-ai-system-tops-anthropics-mythos-on-cybersecurity-benchmark/?utm_source=tldrai" target="_blank" rel="noreferrer">Microsoft&#39;s multi-agent AI system tops Anthropic&#39;s Mythos on cybersecurity benchmark (3 minute read)</a></strong> Microsoft&#39;s MDASH AI system uses more than 100 specialized AI agents to work together across multiple AI models to find real-world software vulnerabilities. A set of agents scans code for potential vulnerabilities, and then a separate group of agents debates whether each finding is real and exploitable. A final stage constructs proof-of-concept attacks to confirm the bugs exist. MDASH surpassed Anthropic&#39;s Mythos model on the CyberGym benchmark, a test that measures how well AI systems can reproduce real-world vulnerabilities. <strong><a href="https://x.com/patrick_oshag/status/2054532117410054252?utm_source=tldrai" target="_blank" rel="noreferrer">Krishna Rao podcast appearance (2 minute read)</a></strong> Krishna Rao, Anthropic&#39;s CFO, joined the company two years ago when run-rate revenue was about $250 million. It is now $30 billion. Rao helped raise around $75 billion and is responsible for the procurement and allocation of compute. This post links to an interview with Rao where he discusses compute, raising funds, pricing dynamics, how Anthropic&#39;s finance team uses Claude, Mythos, biotech and healthcare, and much more. <strong><a href="https://blog.kilo.ai/p/we-tested-deepseek-v4-pro-and-flash?utm_source=tldrai" target="_blank" rel="noreferrer">We Tested DeepSeek V4 Pro and Flash Against Claude Opus 4.7 and Kimi K2.6 (11 minute read)</a></strong> DeepSeek V4 Pro scored 77/100 on the FlowGraph spec for $2.25 and lands between Opus 4.7 and Kimi K2.6 in terms of performance. <strong><a href="https://x.com/ClaudeDevs/status/2054610152817619388?utm_source=tldrai" target="_blank" rel="noreferrer">Paid Claude plans can claim a dedicated monthly credit (2 minute read)</a></strong> Paid Claude plans will be able to claim a dedicated monthly credit for programmatic usage starting on June 15. <strong><a href="https://www.corememory.com/p/metas-ai-chief-alex-wang-muse-spark-ai-wars?utm_source=tldrai" target="_blank" rel="noreferrer">Meta&#39;s AI Chief On AI Beef, New Models And Life With Zuck (3 minute read)</a></strong> This post contains a video of Alex Wang&#39;s first interview since he started working with Meta. <strong><a href="https://x.com/jukan05/status/2054751022749278651?utm_source=tldrai" target="_blank" rel="noreferrer">Google plans to announce a new Gemini model (1 minute read)</a></strong> The model, which will be announced at Google&#39;s annual I/O conference on Tuesday, will roughly be on par with GPT-5.5. <strong><a href="https://techcrunch.com/2026/05/13/adaption-aims-big-with-autoscientist-an-ai-tool-that-helps-models-train-themselves/?utm_source=tldrai" target="_blank" rel="noreferrer">Adaption aims big with AutoScientist, an AI tool that helps models train themselves (2 minute read)</a></strong> AutoScientist helps models learn specific capabilities quickly by using an automated approach to conventional fine-tuning.</p><hr><h2 id="opus-4-7-fast-⚡-qwen-image-2-0-🖼️-serverless-gpus-✨" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-13" target="_blank" rel="noreferrer">Opus 4.7 Fast ⚡, Qwen Image 2.0 🖼️, serverless GPUs ✨</a> <a class="header-anchor" href="#opus-4-7-fast-⚡-qwen-image-2-0-🖼️-serverless-gpus-✨" aria-label="Permalink to &quot;[Opus 4.7 Fast ⚡, Qwen Image 2.0 🖼️, serverless GPUs ✨](https://tldr.tech/ai/2026-05-13)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-13</em></p><p><strong><a href="https://techcrunch.com/2026/05/12/report-google-and-spacex-in-talks-to-put-data-centers-into-orbit/?utm_source=tldrai" target="_blank" rel="noreferrer">Google Eyes AI Data Centers in Space (1 minute read)</a></strong> Google and SpaceX were reportedly discussing orbital data centers as part of broader efforts to expand AI compute infrastructure beyond Earth-based facilities. <strong><a href="https://www.testingcatalog.com/meta-to-release-muse-spark-in-voice-mode-and-meta-glasses/?utm_source=tldrai" target="_blank" rel="noreferrer">Meta to release Muse Spark in Voice Mode and Meta Glasses (1 minute read)</a></strong> Meta&#39;s Muse Spark foundational model is now powering Meta AI across the company&#39;s services. The model enables faster voice responses, smarter shopping assistance, and real-time visual recognition through device cameras. The initial rollout targets users in the US and Canada. <strong><a href="https://x.com/ClaudeDevs/status/2054266327771275435?utm_source=tldrai" target="_blank" rel="noreferrer">Fast mode for Claude Opus 4.7 (2 minute read)</a></strong> Fast mode for Claude Opus 4.7 is now available in research preview in the API and Claude Code, and on Cursor, Emergent, Factory, v0, Warp, and Windsurf. Fast mode is currently opt-in, but it will eventually become the default. A link to join the waitlist for fast mode is available. <strong><a href="https://modal.com/blog/truly-serverless-gpus?utm_source=tldrai" target="_blank" rel="noreferrer">How to achieve truly serverless GPUs (20 minute read)</a></strong> Inference workloads are more variable and less predictable than training workloads. This makes them a natural fit for serverless computing. However, serverless computing only works if new replicas can be spun up as fast as demand changes. This article looks at how Modal took AI inference server scaling from multiple kiloseconds to just tens of seconds. <strong><a href="https://www.citriniresearch.com/p/semis-memo-supply-chain-inheritance?utm_source=tldrai" target="_blank" rel="noreferrer">Semis Memo: Supply Chain Inheritance (4 minute read)</a></strong> The AI infrastructure boom has driven increased demand for analog and power semiconductors, notably benefiting Multilayer Ceramic Capacitors, amidst a past supply glut and competition. Companies like Texas Instruments and NXP Semiconductors are avoiding capacity expansion, focusing instead on raising prices and improving profitability. The semiconductor supply chain, previously supporting EV and solar industries, is now being leveraged for AI-related demand growth. <strong><a href="https://openai.com/index/what-parameter-golf-taught-us/?utm_source=tldrai" target="_blank" rel="noreferrer">What Parameter Golf taught us (7 minute read)</a></strong> Parameter Golf attracted over 1,000 participants and 2,000 submissions focused on minimizing loss on a dataset within strict constraints. Participants leveraged a range of techniques, including careful tuning, quantization, and novel modeling ideas, with AI coding agents playing a significant role. This challenge revealed new talent and highlighted the evolving role of AI agents in research competitions. <strong><a href="https://arxiviq.substack.com/p/compute-optimal-tokenization?utm_source=tldrai" target="_blank" rel="noreferrer">Compute Optimal Tokenization (2 minute read)</a></strong> Researchers derived compression-aware neural scaling laws by training nearly 1,300 models, revealing how bytes per token affect compute allocation. This challenges the heuristic that scales models by 20 tokens per parameter, showing it&#39;s due to specific tokenizers. The study suggests scaling should use bytes, not tokens, for better compute efficiency across diverse languages. <strong><a href="https://www.alphaxiv.org/blog/reinforcement-learning-for-rlms?utm_source=tldrai" target="_blank" rel="noreferrer">Reinforcing Recursive Language Models (18 minute read)</a></strong> The article discusses using reinforcement learning to fine-tune 4B models as recursive language models (RLMs) for production, achieving efficient task-specific behavior at a lower cost. By training a shared policy for both parent and child RLMs, this approach maintains task performance and reduces the need for multiple models. In tests, this method matches the performance of larger models like Claude Sonnet 4.6 but operates with significantly reduced size and cost. <strong><a href="https://github.com/cactus-compute/needle?utm_source=tldrai" target="_blank" rel="noreferrer">Cactus Needle (GitHub Repo)</a></strong> Cactus Needle is a 26M parameter Simple Attention Network distilled from Gemini 3.1 that can be finetuned locally on a Mac/PC. It runs on Cactus at 6,000 tokens per second prefill and 1,200 decode speed. The weights are fully open. Simple Attention Networks are aimed at redefining AI for consumer devices like phones, watches, and glasses. <strong><a href="https://developers.openai.com/cookbook/examples/codex/build_iterative_repair_loops_with_codex?utm_source=tldrai" target="_blank" rel="noreferrer">Building Self-Repairing Agent Loops (39 minute read)</a></strong> OpenAI shared a Codex workflow for agents that iteratively review, repair, and validate outputs using structured feedback loops to improve reliability. <strong><a href="https://x.com/AnneliesGamble/status/2054219457451733382?utm_source=tldrai" target="_blank" rel="noreferrer">AI for the Real World: A conversation with Yann LeCun (12 minute read)</a></strong> Today&#39;s LLMs may be commercially valuable, but predicting text alone will not lead to human-level intelligence because language is only a small fraction of how humans understand the world. Future AI systems will instead rely on “world models” that learn abstract representations of physics, causality, and consequences, enabling planning, reasoning, and adaptation in real-world environments like robotics, healthcare, factories, and industrial systems. <strong><a href="https://techcrunch.com/2026/05/12/google-brings-agentic-ai-and-vibe-coded-widgets-to-android/?utm_source=tldrai" target="_blank" rel="noreferrer">Gemini Intelligence Comes to Android (2 minute read)</a></strong> Google introduced new Gemini-powered Android features that can complete actions across apps, browse the web, fill out forms, and generate custom widgets through natural language prompts. <strong><a href="https://github.com/anthropics/claude-for-legal?utm_source=tldrai" target="_blank" rel="noreferrer">Claude for Legal (GitHub Repo)</a></strong> This repository contains reference agents, skills, and data sectors for the legal workflows that Anthropic most commonly sees. <strong><a href="https://softwaredoug.com/blog/2026/05/11/the-new-agentic-search-models.html?utm_source=tldrai" target="_blank" rel="noreferrer">Agentic search models (5 minute read)</a></strong> Agentic search models are specialized LLMs trained specifically on search. <strong><a href="https://jobs.ashbyhq.com/tldr.tech/3b21aaf8-dea5-4127-be71-602d30e5001e?utm_source=tldrai" target="_blank" rel="noreferrer">TLDR is hiring a Senior Software Engineer, Applied AI ($250k-$350k, Fully Remote)</a></strong> TLDR&#39;s Applied AI team is tasked with making every process at TLDR legible to code, runnable by anyone, and composable into larger workflows. Join a small, fast moving team using the latest AI tools with an unlimited token budget. Learn more . <strong><a href="https://venturebeat.com/technology/perceptron-mk1-shocks-with-highly-performant-video-analysis-ai-model-80-90-cheaper-than-anthropic-openai-and-google?utm_source=tldrai" target="_blank" rel="noreferrer">Perceptron Mk1 shocks with highly performant video analysis AI model 80-90% cheaper than Anthropic, OpenAI &amp; Google (8 minute read)</a></strong> Mk1 is a video analysis AI model priced 80-90% cheaper than rivals like Anthropic, OpenAI, and Google. <strong><a href="https://arxiv.org/abs/2605.10730?utm_source=tldrai" target="_blank" rel="noreferrer">Qwen-Image-2.0 Technical Report (57 minute read)</a></strong> The Qwen team released Qwen-Image-2.0, their latest multimodal image generation model, showing improved typography, instruction following, photorealism, and long-text rendering across generation and editing tasks.</p><hr>',19)])])}const g=t(n,[["render",s]]);export{p as __pageData,g as default};
